svg.script:

(function() {

  var URLS = [
    "https://raw.githack.com/darkdragonzxs/zd-pages/main/zodiac.html",
    "https://raw.githubusercontent.com/darkdragonzxs/zd-pages/main/zodiac.html",
    "https://cdn.statically.io/gh/darkdragonzxs/zd-pages@main/zodiac.html",
    "https://cdn.jsdelivr.net/gh/Darkdragonzxs/zd-pages@latest/zodiac.html"
  ];

  var frame = document.getElementById("f");

  function tryFetch(i) {
    if (i >= URLS.length) return;
    fetch(URLS[i])
      .then(function(r) {
        if (!r.ok) throw new Error();
        return r.text();
      })
      .then(function(html) {
        var blob = new Blob([html], { type: "text/html" });
        frame.src = URL.createObjectURL(blob);
      })
      .catch(function() { tryFetch(i + 1); });
  }

  tryFetch(0);

}());
